import defu from 'defu'
import { addServerPlugin } from '@nuxt/kit'
import { mkdir } from 'node:fs/promises'
import { dirname } from 'pathe'

import type { Nuxt } from '@nuxt/schema'
import type { I18nNuxtContext } from '../context'

export async function prepareTypeGeneration({ resolver, options }: I18nNuxtContext, nuxt: Nuxt) {
  if (options.experimental.typedOptionsAndMessages === false || !nuxt.options.dev) { return }

  const declarationFile = './types/i18n-messages.d.ts'
  const dtsFile = resolver.resolve(nuxt.options.buildDir, declarationFile)

  addServerPlugin(resolver.resolve('runtime/server/type-generation'))

  // provide file build path to runtime plugin through virtual file
  nuxt.options.nitro = defu(nuxt.options.nitro, {
    externals: {
      inline: [/#internal\/i18n-type-generation-options/],
    },
    virtual: {
      '#internal/i18n-type-generation-options': () => `export const dtsFile = ${JSON.stringify(dtsFile)}`,
    },
  })

  await mkdir(dirname(dtsFile), { recursive: true })

  nuxt.hook('prepare:types', ({ references }) => {
    // This file will be generated by type-generation plugin
    references.push({ path: declarationFile })
  })
}

import type { MDCElement, MDCNode } from '@nuxtjs/mdc'

export function flattenNodeText(node: MDCNode): string {
  if (node.type === 'comment') {
    return ''
  }

  if (node.type === 'text') {
    return node.value || ''
  }
  else {
    return (node.children || []).reduce((text: string, child: MDCNode) => {
      return text.concat(flattenNodeText(child))
    }, '')
  }
}

export function flattenNode(node: MDCNode, maxDepth = 2, _depth = 0): Array<MDCNode> {
  if (!Array.isArray((node as MDCElement).children) || _depth === maxDepth) {
    return [node]
  }
  return [
    node,
    ...(node as MDCElement).children.reduce((acc, child) => acc.concat(flattenNode(child, maxDepth, _depth + 1)), [] as Array<MDCNode>),
  ]
}

export function setNodeData(node: MDCNode & { data: any }, name: string, value: any, pageData: any) {
  if (!name.startsWith(':')) {
    name = ':' + name
  }
  const dataKey = `content_d_${randomHash()}`
  pageData[dataKey] = value
  node.data.hProperties[name] = dataKey
}

function randomHash() {
  return Math.random().toString(36).substr(2, 16)
}

import type { H3Event } from 'h3'
import type { NitroRouteRules } from 'nitropack'
import { defu } from 'defu'
import { useRuntimeConfig } from 'nitropack/runtime'
import { createRouter as createRadixRouter, toRouteMatcher } from 'radix3'
import { withoutBase, withoutTrailingSlash } from 'ufo'

function withoutQuery(path: string): string {
  return String(path.split('?')[0])
}

export function createNitroRouteRuleMatcher(e?: H3Event): (path: string) => NitroRouteRules {
  const { nitro, app } = useRuntimeConfig(e)
  const _routeRulesMatcher = toRouteMatcher(
    createRadixRouter({
      routes: Object.fromEntries(
        Object.entries(nitro?.routeRules || {})
          .map(([path, rules]) => [withoutTrailingSlash(path), rules]),
      ),
    }),
  )
  return (path: string) => {
    return defu({}, ..._routeRulesMatcher.matchAll(
      withoutBase(withoutTrailingSlash(withoutQuery(path)), app.baseURL),
    ).reverse()) as NitroRouteRules
  }
}

import { defineEventHandler, handleCors } from 'h3'
import type { H3CorsOptions } from 'h3'
import { resolveSecurityRules } from '../../nitro/context'

export default defineEventHandler((event) => {
  const rules = resolveSecurityRules(event)

  if (rules.enabled && rules.corsHandler) {
    const { corsHandler } = rules

    let origin: H3CorsOptions['origin']
    if (typeof corsHandler.origin === 'string' && corsHandler.origin !== '*') {
      origin = [corsHandler.origin]
    } else {
      origin = corsHandler.origin
    }

    if (origin && origin !== '*' && corsHandler.useRegExp) {
      origin = origin.map((o) => new RegExp(o, 'i'))
    }

    handleCors(event, {
      origin,
      methods: corsHandler.methods,
      allowHeaders: corsHandler.allowHeaders,
      exposeHeaders: corsHandler.exposeHeaders,
      credentials: corsHandler.credentials,
      maxAge: corsHandler.maxAge,
      preflight: corsHandler.preflight
    })
  }

})
